// Verify the bridge secret, resolve the transcript, dedupe on meetingId (bot is at-least-once).
const got = $input.first().json.headers?.['x-gaiada-bridge-secret'];
if (!got || got !== $env.N8N_BRIDGE_SECRET) throw new Error('bad bridge secret');
const e = $input.first().json.body ?? {};
if (e.v !== 1) throw new Error(`unexpected envelope version ${e.v}`);
if (!e.tenantId) throw new Error('tenantId required');
const transcript = (e.transcript && String(e.transcript).trim()) ? String(e.transcript) : '';
if (!transcript) throw new Error('v1 requires body.transcript (audioRef-only transcription is a later enhancement)');
const store = $getWorkflowStaticData('global');
store.seen = store.seen || {};
const key = e.meetingId || '';
const dup = key ? Object.prototype.hasOwnProperty.call(store.seen, key) : false;
if (key && !dup) { store.seen[key] = Date.now(); const ids = Object.keys(store.seen); if (ids.length > 1000) for (const k of ids.slice(0, ids.length - 1000)) delete store.seen[k]; }
return [{ json: { dup, tenantId: e.tenantId, meetingId: key, title: e.title ?? null, transcript } }];

const raw = $input.first().json.data ?? $input.first().json.body ?? '';
const line = String(raw).split('\n').find((l) => l.startsWith('data:')) ?? '';
const rpc = JSON.parse(line.slice(5).trim());
if (rpc.result?.isError) throw new Error(rpc.result.content?.[0]?.text ?? 'llm.summarize error');
const mom = rpc.result?.content?.[0]?.text ?? '';
const v = $('Verify + dedupe + resolve transcript').first().json;
return [{ json: { ...v, mom } }];

const raw = $input.first().json.data ?? $input.first().json.body ?? '';
const line = String(raw).split('\n').find((l) => l.startsWith('data:')) ?? '';
const rpc = JSON.parse(line.slice(5).trim());
if (rpc.result?.isError) throw new Error(rpc.result.content?.[0]?.text ?? 'llm.extract prd error');
let parsed = {}; try { parsed = JSON.parse(rpc.result?.content?.[0]?.text ?? '{}'); } catch { parsed = {}; }
const prev = $('Parse MOM').first().json;
return [{ json: { ...prev, prd: { content: parsed.content ?? '', confidence: (typeof parsed.confidence === 'number' ? parsed.confidence : null) } } }];

