const raw = $input.first().json.data ?? $input.first().json.body ?? '';
const line = String(raw).split('\n').find((l) => l.startsWith('data:')) ?? '';
const rpc = JSON.parse(line.slice(5).trim());
if (rpc.result?.isError) throw new Error(rpc.result.content?.[0]?.text ?? 'llm.extract scope error');
let parsed = {}; try { parsed = JSON.parse(rpc.result?.content?.[0]?.text ?? '{}'); } catch { parsed = {}; }
const prev = $('Parse report').first().json;
const scope = { content: parsed.content ?? '', confidence: (typeof parsed.confidence === 'number' ? parsed.confidence : null) };
// Assemble the pipeline.createRun arguments; drop null confidence so the tool schema stays happy.
const stage = (track, name, art) => { const s = { track, name, status: 'done', artifactRef: art.content }; if (typeof art.confidence === 'number') s.confidence = art.confidence; return s; };
const args = { tenantId: prev.tenantId, sourceMeetingId: prev.meetingId || undefined, title: prev.title || undefined, momRef: prev.mom || undefined, stages: [ stage('delivery', 'prd_extract', prev.prd), stage('report', 'report_extract', prev.report), stage('scope', 'scope_extract', scope) ] };
return [{ json: { args, prdConfidence: prev.prd.confidence } }];

const raw = $input.first().json.data ?? $input.first().json.body ?? '';
const line = String(raw).split('\n').find((l) => l.startsWith('data:')) ?? '';
const rpc = JSON.parse(line.slice(5).trim());
if (rpc.result?.isError) throw new Error(rpc.result.content?.[0]?.text ?? 'pipeline.createRun failed (a medium+ write would suspend here)');
const run = JSON.parse(rpc.result?.content?.[0]?.text ?? '{}');
return [{ json: { runId: run.id, deduped: run.deduped ?? false, prdConfidence: $('Assemble createRun args').first().json.prdConfidence } }];
